type Item = {
    nom: string;
    prixUnitaire: number | null;
    quantite: number;
};

type Panier = {
    items: Item[];
    taxe: number; // Taux de taxe en pourcentage (ex: 20 pour 20%)
};

type ErreurPanier = 
    | { type: 'PANIER_VIDE' }
    | { type: 'ITEM_SANS_PRIX'; nomItem: string }
    | { type: 'TAUX_TAXE_NEGATIF' };

function calculerTotalTTC(panier: Panier): number | ErreurPanier {
    if (panier.items.length === 0) {
        return { type: 'PANIER_VIDE' };
    }

    if (panier.taxe < 0) {
        return { type: 'TAUX_TAXE_NEGATIF' };
    }

    const totalHT = panier.items.reduce((acc, item) => {
        if (item.prixUnitaire === null) {
            return { type: 'ITEM_SANS_PRIX', nomItem: item.nom };
        }
        return acc + item.prixUnitaire * item.quantite;
    }, 0);

    if ('type' in totalHT) {
        return totalHT;
    }

    const totalTTC = totalHT * (1 + panier.taxe / 100);
    return totalTTC;
}
